function longestWord(words) {
    words.sort();
    const builtWords = new Set();
    let result = '';

    for (const word of words) {
        if (word.length === 1 || builtWords.has(word.slice(0, -1))) {
            result = (word.length > result.length) ? word : result;
            builtWords.add(word);
        }
    }

    return result;
}
